section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "agent-architectures-output",
  "required": [
    "memory_size_limit",
    "memory_summarization",
    "tool_count",
    "fsm_states",
    "planning_enabled",
    "reflection_enabled",
    "idle_evict_iterations",
    "forbidden_seen"
  ],
  "properties": {
    "memory_size_limit": {
      "description": "Token budget for memory."
    },
    "memory_summarization": {
      "description": "Compression enabled."
    },
    "tool_count": {
      "description": "Tools registered."
    },
    "fsm_states": {
      "description": "States in the FSM."
    },
    "planning_enabled": {
      "description": "Planning step present."
    },
    "reflection_enabled": {
      "description": "Reflection step present."
    },
    "idle_evict_iterations": {
      "description": "K for eviction policy."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
